import LandingPage from './content/pages/LandingPage/LandingPage'
import { Route, Routes } from 'react-router-dom'
import SignInPage from './content/pages/Auth/SingInpage'
import SignUpPage from './content/pages/Auth/SingUpPage';
import NavBar from './commons/NavBar/NavBar';
import { Usercontroller } from './content/dashboards/userController/usercontroller';


function App() {

  return (
    <>
      <NavBar/>
      <Routes>
        <Route path="/" element={<LandingPage/>}/>
        <Route path="/signin" element={<SignInPage/>}/>
        <Route path="/signup" element={<SignUpPage/>}/>
        <Route path='/usermanagment' element={<Usercontroller/>}/>
      </Routes>
    </>
  );
}

export default App;
